export interface QualitySnapshot {
  /**
   * @displayName Quality Snapshot
   * @description Unique system identifier - GUID generated by system
   * @uiConstraints NEVER create input fields for this ID
   */
  id: string;
  /**
   * @displayName Snapshot Name
   * @description Human-readable record identifier
   * @validationRule Required for create/update operations
   */
  snapshotname: string;
  /**
   * @displayName Failed
   */
  failed?: number;
  /**
   * @displayName Passed
   */
  passed?: number;
  /**
   * @displayName Pass Rate
   */
  passrate?: number;
  /**
   * @displayName Total Tests
   */
  totaltests?: number;
}

export const _QualitySnapshot = 'QualitySnapshot' as const;